import{_ as d,o as e,c as a,ac as i}from"./chunks/framework.DnBnwVZk.js";const p=JSON.parse('{"title":"MySQL性能优化","description":"","frontmatter":{"date":"2023-05-27T18:58:22.000Z","categories":["MySQL"],"tags":["MySQL"],"publish":false},"headers":[],"relativePath":"views/MySQL/MySQLOptimize.md","filePath":"views/MySQL/MySQLOptimize.md","lastUpdated":1775654397000}'),h={name:"views/MySQL/MySQLOptimize.md"};function r(o,t,n,l,s,_){return e(),a("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1685213902000"},[...t[0]||(t[0]=[i('<h1 id="mysql性能优化" tabindex="-1">MySQL性能优化 <a class="header-anchor" href="#mysql性能优化" aria-label="Permalink to &quot;MySQL性能优化&quot;">​</a></h1><h2 id="简单情况-缺少索引" tabindex="-1">简单情况，缺少索引 <a class="header-anchor" href="#简单情况-缺少索引" aria-label="Permalink to &quot;简单情况，缺少索引&quot;">​</a></h2><p>索引只有batch_id，查询实际上是 select * from w_table where batch_id = 1 and status = 2</p><h2 id="索引不能乱加-在错误的列上建立索引导致磁盘空间爆炸" tabindex="-1">索引不能乱加！！！在错误的列上建立索引导致磁盘空间爆炸 <a class="header-anchor" href="#索引不能乱加-在错误的列上建立索引导致磁盘空间爆炸" aria-label="Permalink to &quot;索引不能乱加！！！在错误的列上建立索引导致磁盘空间爆炸&quot;">​</a></h2><p>在timestamp字段建立索引，导致数据空间16G的情况下，索引空间占用达到60G！</p><p><strong>原因？？？</strong></p><h2 id="索引下推" tabindex="-1">索引下推 <a class="header-anchor" href="#索引下推" aria-label="Permalink to &quot;索引下推&quot;">​</a></h2><h2 id="慢sql优化" tabindex="-1">慢SQL优化 <a class="header-anchor" href="#慢sql优化" aria-label="Permalink to &quot;慢SQL优化&quot;">​</a></h2><ol><li>索引下推变为顺序查询（MRR）</li></ol><p>优化前</p><p><code>select c1,c2 from tableA where relation_id_1 in (1,2,3) and relation_id_2 in (400,500,600)</code></p><p>此时索引下推，Explain表现</p><table tabindex="0"><thead><tr><th>id</th><th>select_type</th><th>table</th><th>partitions</th><th>type</th><th>possible_keys</th><th>key</th><th>key_len</th><th>ref</th><th>rows</th><th>filtered</th><th>Extra</th></tr></thead><tbody><tr><td>1</td><td>SIMPLE</td><td>tableA</td><td>NULL</td><td>range</td><td>idx_C2_C3,idx_C2_C1</td><td>idx_C2_C3</td><td>8</td><td>NULL</td><td>540780</td><td>5</td><td>Using index condition; Using where</td></tr></tbody></table><p>优化业务逻辑，<code>relation_id_1 in (1,2,3)</code>优化为多个<code>relation_id_1 = 1</code>（边缘定时任务，业务可接受），整个SQL优化为</p><p><code>select c1,c2 from tableA where relation_id_1 = 1 and relation_id_2 in (400,500,600)</code></p><table tabindex="0"><thead><tr><th>id</th><th>select_type</th><th>table</th><th>partitions</th><th>type</th><th>possible_keys</th><th>key</th><th>key_len</th><th>ref</th><th>rows</th><th>filtered</th><th>Extra</th></tr></thead><tbody><tr><td>改造前</td><td>SIMPLE</td><td>tableA</td><td>NULL</td><td>range</td><td>idx_C2_C3,idx_C2_C1</td><td>idx_C2_C3</td><td>8</td><td>NULL</td><td>540780</td><td>5</td><td>Using index condition; Using where</td></tr><tr><td>改造后</td><td>SIMPLE</td><td>tableA</td><td>NULL</td><td>range</td><td>idx_C2_C3,idx_C2_C1</td><td>idx_C2_C1</td><td>17</td><td>NULL</td><td>172</td><td>10</td><td>Using index condition; Using where; Using MRR</td></tr></tbody></table><p>注意，改造前后都使用了索引下推技术（Using index condition），但是改造后多了Using MRR</p>',17)])])}const b=d(h,[["render",r]]);export{p as __pageData,b as default};
